// Generated by OrchestKit Claude Plugin
// Created: 2026-04-02

/**
 * Webhook Forwarder Coverage Validator
 *
 * Ensures every hook event type in hooks.json has webhook forwarder coverage
 * via EITHER a standalone lifecycle/webhook-forwarder entry in hooks.json OR
 * an inlined webhookForwarder() call in the dispatcher source code.
 *
 * Fails CI if a new event type or matcher group is added without coverage.
 *
 * @see https://github.com/yonatangross/orchestkit/issues/1256
 */

import { describe, test, expect } from 'vitest';
import { readFileSync, existsSync } from 'node:fs';
import { join, resolve } from 'node:path';

// ---------------------------------------------------------------------------
// Parse hooks.json
// ---------------------------------------------------------------------------

const hooksJsonPath = join(__dirname, '..', '..', 'hooks.json');
const hooksJson = JSON.parse(readFileSync(hooksJsonPath, 'utf8'));
const hookEvents: Record<string, Array<{ matcher?: string; hooks: Array<{ type: string; command?: string; async?: boolean }> }>> = hooksJson.hooks;

// Source root for resolving dispatcher .ts files
const srcRoot = resolve(__dirname, '..');

// ---------------------------------------------------------------------------
// Intentional exclusions — document any events deliberately not forwarded
// ---------------------------------------------------------------------------

const INTENTIONAL_EXCLUSIONS = new Set<string>([
  // Format: 'EventName' or 'EventName:matcherString'
  // Currently empty — all events should be forwarded
]);

// ---------------------------------------------------------------------------
// Detection: standalone webhook-forwarder in hooks.json
// ---------------------------------------------------------------------------

interface CoverageEntry {
  event: string;
  matcher: string; // '*' for unscoped
  standalone: boolean;
  inlined: boolean;
  dispatcherPath?: string;
}

/**
 * Check if a hook group contains a standalone webhook-forwarder command.
 */
function hasStandaloneForwarder(hooks: Array<{ type: string; command?: string }>): boolean {
  return hooks.some(
    (h) => h.type === 'command' && typeof h.command === 'string' && h.command.includes('lifecycle/webhook-forwarder'),
  );
}

/**
 * Extract the dispatcher hook path from a command hook entry.
 * Returns the path like "pretool/bash/sync-bash-dispatcher" or undefined.
 */
function extractHookPath(command: string): string | undefined {
  const match = command.match(/run-hook\.mjs\s+(\S+)/);
  return match?.[1];
}

/**
 * Check if a dispatcher source file contains an inlined webhookForwarder call.
 */
function hasInlinedForwarder(hookPath: string): boolean {
  // Skip the webhook-forwarder itself
  if (hookPath === 'lifecycle/webhook-forwarder') return false;

  const sourceFile = join(srcRoot, `${hookPath}.ts`);
  if (!existsSync(sourceFile)) return false;

  const content = readFileSync(sourceFile, 'utf8');
  return content.includes('webhookForwarder');
}

// ---------------------------------------------------------------------------
// Build complete coverage map
// ---------------------------------------------------------------------------

function buildCoverageMap(): CoverageEntry[] {
  const entries: CoverageEntry[] = [];

  for (const [event, groups] of Object.entries(hookEvents)) {
    for (const group of groups) {
      const matcher = group.matcher ?? '*';
      const standalone = hasStandaloneForwarder(group.hooks);

      // Check if any non-forwarder dispatcher in this group has inlined the forwarder
      let inlined = false;
      let dispatcherPath: string | undefined;

      for (const hook of group.hooks) {
        if (hook.type === 'command' && typeof hook.command === 'string') {
          const hookPath = extractHookPath(hook.command);
          if (hookPath && hookPath !== 'lifecycle/webhook-forwarder') {
            dispatcherPath = hookPath;
            if (hasInlinedForwarder(hookPath)) {
              inlined = true;
            }
          }
        }
      }

      entries.push({ event, matcher, standalone, inlined, dispatcherPath });
    }
  }

  return entries;
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('Webhook Forwarder Coverage Validator', () => {
  const coverageMap = buildCoverageMap();

  test('hooks.json has the expected number of event types', () => {
    const eventCount = Object.keys(hookEvents).length;
    // Guard: if this fails, a new event was added — update the test AND add forwarder coverage
    expect(eventCount).toBe(27);
  });

  test('detects standalone webhook-forwarder entries', () => {
    const standaloneEvents = coverageMap.filter((e) => e.standalone);
    // 20 events have standalone + FileChanged (after fix) = 21
    // Each of these events has lifecycle/webhook-forwarder registered in hooks.json
    expect(standaloneEvents.length).toBeGreaterThanOrEqual(20);
  });

  test('no inlined webhookForwarder in dispatchers (decoupled in v7.29.0)', () => {
    const inlinedEntries = coverageMap.filter((e) => e.inlined);
    // v7.29.0: all inline forwarder calls removed — standalone hooks.json entries handle telemetry
    expect(inlinedEntries.length).toBe(0);
  });

  test('every event type and matcher group has webhook forwarder coverage', () => {
    const gaps: string[] = [];

    for (const entry of coverageMap) {
      const key = entry.matcher === '*' ? entry.event : `${entry.event}:${entry.matcher}`;

      if (INTENTIONAL_EXCLUSIONS.has(key)) continue;

      if (!entry.standalone && !entry.inlined) {
        const dispatcherInfo = entry.dispatcherPath ? ` (dispatcher: ${entry.dispatcherPath})` : '';
        gaps.push(`  ${key}${dispatcherInfo}`);
      }
    }

    expect(
      gaps,
      `Webhook forwarder coverage gaps found:\n${gaps.join('\n')}\n\n` +
        'Fix: add lifecycle/webhook-forwarder as async hook entry in hooks.json for this event.',
    ).toEqual([]);
  });

  test('INTENTIONAL_EXCLUSIONS contains no stale entries', () => {
    const coveredKeys = new Set<string>();
    for (const entry of coverageMap) {
      const key = entry.matcher === '*' ? entry.event : `${entry.event}:${entry.matcher}`;
      if (entry.standalone || entry.inlined) {
        coveredKeys.add(key);
      }
    }

    const stale: string[] = [];
    for (const exclusion of INTENTIONAL_EXCLUSIONS) {
      if (coveredKeys.has(exclusion)) {
        stale.push(exclusion);
      }
    }

    expect(
      stale,
      `These INTENTIONAL_EXCLUSIONS now have coverage and should be removed:\n${stale.join('\n')}`,
    ).toEqual([]);
  });

  test('coverage map includes all matcher-scoped events', () => {
    // Matcher-scoped events must have per-matcher entries
    const matcherScopedEvents = ['PreToolUse', 'PostToolUse', 'PostToolUseFailure', 'PermissionRequest'];

    for (const event of matcherScopedEvents) {
      const groups = hookEvents[event] || [];
      const mapEntries = coverageMap.filter((e) => e.event === event);
      expect(mapEntries.length, `${event} should have ${groups.length} coverage entries`).toBe(groups.length);
    }
  });
});
